useEffect(() => {
  // Setup: o que acontece quando o efeito roda
  const id = setInterval(() => {
    setSeconds(s => s + 1);
  }, 1000);

  // Cleanup: o que acontece quando o componente
  // desmonta OU antes do efeito rodar novamente
  return () => {
    clearInterval(id);
  };
}, []);

import { useState, useEffect } from 'react';

function WindowSize() {
  const [width, setWidth] = useState(window.innerWidth);

  useEffect(() => {
    const handleResize = () => setWidth(window.innerWidth);

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return <p>Largura: {width}px</p>;
}

function ChatRoom({ roomId }) {
  useEffect(() => {
    const connection = connectToRoom(roomId);
    console.log(`Conectado à sala ${roomId}`);

    return () => {
      connection.disconnect();
      console.log(`Desconectado da sala ${roomId}`);
    };
  }, [roomId]);
  // Quando roomId muda: desconecta da sala anterior,
  // depois conecta na nova sala
}

useEffect(() => {
  let cancelled = false;

  fetch(`/api/users/${userId}`)
    .then(res => res.json())
    .then(data => {
      if (!cancelled) {
        setUser(data);
      }
    });

  return () => {
    cancelled = true;
  };
}, [userId]);
